#include<bits/stdc++.h>
using namespace std;
int n,fa[300010],siz[300010];
queue<pair<int,int>> vec;
map<int,int> mp[300010];
int find(int x)
{
    return(x==fa[x]?x:fa[x]=find(fa[x]));
}
void merge(int x,int y)
{
    int a=find(x),b=find(y);
    if(a==b)
    {
        return;
    }
    if(mp[a].size()<mp[b].size())
    {
        swap(a,b);
    }
    for(auto i:mp[b])
    {
        if(mp[a][i.first])
        {
            vec.push({mp[a][i.first],i.second});
        }
        else
        {
            mp[a][i.first]=i.second;
        }
    }
    fa[b]=a;
    siz[a]+=siz[b];
}
int main()
{
    int n,m,k;
    scanf("%d%d%d",&n,&m,&k);
    for(int i=1;i<=n;i++)
    {
        fa[i]=i;
        siz[i]=1;
    }
    for(int i=1;i<=m;i++)
    {
        int u,v,w;
        scanf("%d%d%d",&u,&v,&w);
        swap(u,v);
        if(mp[u][w])
        {
            vec.push({mp[u][w],v});
        }
        else
        {
            mp[u][w]=v;
        }
    }
    while(!vec.empty())
    {
        merge(vec.front().first,vec.front().second);
        vec.pop();
    }
    long long ans=0;
    for(int i=1;i<=n;i++)
    {
        if(i==find(i))
        {
            ans+=1ll*siz[i]*(siz[i]-1)/2;
        }
    }
    printf("%lld",ans);
    return 0;
}
